using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now demonstrate a case where metadata is NOT available.
// Use a source-gen context that only knows about Person.
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new PersonOnlyContext()
};

if (restrictedOptions.TryGetTypeInfo<Order>(out JsonTypeInfo<Order>? orderInfo))
{
    Console.WriteLine($"TryGetTypeInfo<Order> succeeded: {orderInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Order> returned false — metadata not available");
}

